var leftRightDifference = function(nums) {
    const n = nums.length;
    const left = Array(n);
    const right = Array(n);
    let ltotal = 0;
    let rtotal = 0;

    for (let i = 0; i < n; i++) {
        left[i] = ltotal;
        ltotal += nums[i];

        const j = n - 1 - i;
        right[j] = rtotal;
        rtotal += nums[j];
    }

    const res = Array(n);

    for (let i = 0; i < n; i++) {
        res[i] = Math.abs(left[i] - right[i]);
    }

    return res;
};
